"""WorkflowRuntime — mantis 워크플로우 실행 엔진."""

from __future__ import annotations

import logging
import time
from typing import Any, AsyncIterator

from mantis.models.node import NodeInfo
from mantis.runtime.context import RunContext
from mantis.runtime.parse import parse_workflow
from mantis.runtime.plan import topological_sort
from mantis.runtime.port_store import PortStore
from mantis.runtime.stream_manager import StreamManager
from mantis.runtime.route_resolver import RouteResolver
from mantis.runtime.runners.default import DefaultRunner
from mantis.runtime.runners.agent import AgentRunner
from mantis.runtime.runners.router import RouterRunner
from mantis.runtime.runners.provider import ProviderRunner
from mantis.runtime.runners.io import IORunner
from mantis.runtime.runners.bypass import BypassRunner

logger = logging.getLogger(__name__)

# 기본 runner 매핑
_DEFAULT_RUNNERS = {
    "agents": AgentRunner(),
    "xgen": AgentRunner(),
    "router": RouterRunner(),
    "startnode": IORunner(),
    "endnode": IORunner(),
    "model": ProviderRunner(),
    "mcp": ProviderRunner(),
}
_FALLBACK_RUNNER = DefaultRunner()
_BYPASS_RUNNER = BypassRunner()


class WorkflowRuntime:
    """mantis 워크플로우 실행 엔진.

    워크플로우 그래프(nodes + edges)를 받아서 논리적 흐름으로 실행한다.
    상태를 안 가진다. 호출마다 독립 실행.
    """

    def __init__(
        self,
        *,
        runners: dict[str, Any] | None = None,
        hooks: list[Any] | None = None,
        # Providers — 꽂으면 AgentRunner 등에서 자동 활용
        model: Any | None = None,         # LLMProvider (에이전트 노드용)
        tools: list[Any] | None = None,   # @tool 함수 또는 ToolSpec 목록
        search: Any | None = None,        # GraphToolManager / SearchProvider
        sandbox: Any | None = None,       # SandboxProvider (DockerSandbox)
        workflows: Any | None = None,     # WorkflowStore
        state: Any | None = None,         # StateStore
    ):
        self._runners = {**_DEFAULT_RUNNERS, **(runners or {})}
        self._hooks = list(hooks or [])
        self._model = model
        self._search = search
        self._sandbox = sandbox
        self._workflows = workflows
        self._state = state

        # ToolRegistry 구성
        self._registry = self._build_registry(tools)

        # sandbox → ToolGenerator, ToolTester 자동 활성화
        self._tool_generator = None
        self._tool_tester = None
        if sandbox:
            self._setup_sandbox(sandbox)

        # workflows → WorkflowGenerator 자동 활성화
        self._workflow_generator = None
        if workflows and model:
            self._setup_workflows(workflows, model)

    def _build_registry(self, tools: list[Any] | None) -> Any:
        """tools를 ToolRegistry로 구성."""
        try:
            from mantis.tools.registry import ToolRegistry
            from mantis.tools.decorator import ToolSpec
        except ImportError:
            return None

        registry = ToolRegistry()
        for t in (tools or []):
            if isinstance(t, ToolSpec):
                registry.register(t)
            elif hasattr(t, "_tool_spec"):
                registry.register(t._tool_spec)
        return registry

    def _setup_sandbox(self, sandbox: Any) -> None:
        """sandbox → ToolGenerator + ToolTester 활성화."""
        try:
            from mantis.generate.tool_generator import ToolGenerator
            from mantis.testing.tool_tester import ToolTester

            self._tool_tester = ToolTester(sandbox=sandbox)
            if self._model and self._registry:
                self._tool_generator = ToolGenerator(
                    model=self._model,
                    sandbox=sandbox,
                    registry=self._registry,
                )
            logger.info("WorkflowRuntime: sandbox 활성화 — ToolGenerator + ToolTester")
        except ImportError:
            logger.debug("WorkflowRuntime: generate/testing 모듈 없음, sandbox 비활성")

    def _setup_workflows(self, workflows: Any, model: Any) -> None:
        """workflows → WorkflowGenerator 활성화."""
        try:
            from mantis.workflow.generator import WorkflowGenerator

            if self._registry:
                self._workflow_generator = WorkflowGenerator(
                    model=model,
                    registry=self._registry,
                    store=workflows,
                )
            logger.info("WorkflowRuntime: workflows 활성화 — WorkflowGenerator")
        except ImportError:
            logger.debug("WorkflowRuntime: workflow 모듈 없음, workflows 비활성")

    async def execute(
        self,
        workflow_data: dict,
        input_data: dict | None = None,
    ) -> AsyncIterator[dict]:
        """워크플로우 실행 → 이벤트 스트림."""

        # ── PARSE ──
        nodes, edges = parse_workflow(workflow_data)
        if not nodes:
            yield {"type": "workflow_error", "data": {"error": "노드가 없습니다"}}
            return

        # endnode 식별
        endnode_ids = [nid for nid, n in nodes.items() if n.function_id == "endnode"]

        # ── PLAN ──
        try:
            execution_order = topological_sort(nodes, edges)
        except ValueError as e:
            yield {"type": "workflow_error", "data": {"error": str(e)}}
            return

        # ── RunContext 생성 ──
        stream_manager = StreamManager()
        ctx = RunContext(
            nodes=nodes,
            edges=edges,
            execution_order=execution_order,
            port_store=PortStore(stream_manager, edges),
            stream_manager=stream_manager,
            route_resolver=RouteResolver(edges),
            hooks=self._hooks,
            input_data=input_data or {},
            endnode_ids=endnode_ids,
            # Providers
            tool_registry=self._registry,
            search=self._search,
            sandbox=self._sandbox,
            workflows=self._workflows,
            state=self._state,
            model=self._model,
        )

        yield {
            "type": "workflow_start",
            "data": {"node_count": len(nodes), "edge_count": len(edges)},
        }

        # ── PLAN 이벤트 ──
        yield {
            "type": "execution_plan",
            "data": {
                "order": execution_order,
                "node_count": len(execution_order),
            },
        }

        # ── EXECUTE ──
        try:
            async for event in self._execute_loop(ctx):
                yield event
        except Exception as e:
            logger.exception("워크플로우 실행 실패")
            yield {"type": "workflow_error", "data": {"error": str(e)}}
            return
        finally:
            # ── FINALIZE ──
            stream_manager.cleanup()
            for hook in self._hooks:
                if hasattr(hook, "on_complete"):
                    results = ctx.port_store.collect_endnodes(ctx.endnode_ids)
                    await hook.on_complete(results)

        # 최종 결과
        results = ctx.port_store.collect_endnodes(ctx.endnode_ids)
        yield {"type": "workflow_complete", "data": results}

    async def execute_collect(
        self,
        workflow_data: dict,
        input_data: dict | None = None,
    ) -> dict:
        """워크플로우 실행 → 최종 결과 dict."""
        result = {}
        async for event in self.execute(workflow_data, input_data):
            if event["type"] == "workflow_complete":
                result = event["data"]
            elif event["type"] == "workflow_error":
                raise RuntimeError(event["data"].get("error", "unknown"))
        return result

    async def _execute_loop(self, ctx: RunContext) -> AsyncIterator[dict]:
        """EXECUTE 단계 — 메인 루프. if/elif 없이 runner 디스패치."""

        for node_id in ctx.execution_order:
            if node_id in ctx.excluded:
                yield {"type": "node_skip", "data": {"node_id": node_id, "reason": "excluded"}}
                continue

            node = ctx.nodes[node_id]

            # bypass 체크
            if node.bypass:
                runner = _BYPASS_RUNNER
                yield {"type": "node_skip", "data": {"node_id": node_id, "reason": "bypass"}}
            else:
                # runner 디스패치 (if/elif 없음)
                runner = self._runners.get(node.function_id) or self._runners.get(node.category_id) or _FALLBACK_RUNNER

            # 포트 와이어링
            inputs = ctx.port_store.wire(node)

            node_start_time = time.time()

            yield {"type": "node_start", "data": {
                "node_id": node_id,
                "function_id": node.function_id,
                "name": node.name,
                "input_keys": list(inputs.keys()) if isinstance(inputs, dict) else [],
                "timestamp": node_start_time,
            }}

            # Hook before
            for hook in ctx.hooks:
                if hasattr(hook, "before_node"):
                    inputs = await hook.before_node(node, inputs)

            # 실행
            result = await runner.run(node, inputs, ctx)

            # Hook after
            for hook in ctx.hooks:
                if hasattr(hook, "after_node"):
                    await hook.after_node(node, result)

            # 결과 저장
            ctx.port_store.store(node, result)

            # 라우팅 평가 (router 노드면)
            if node.function_id == "router" and ctx.route_resolver:
                selected = ctx.route_resolver.evaluate(node, result, ctx.excluded)
                if selected:
                    yield {"type": "route_decision", "data": {"node_id": node_id, "selected_port": selected}}

            # 중간 이벤트 flush
            for event in ctx.flush_events():
                yield event

            yield {"type": "node_complete", "data": {
                "node_id": node_id,
                "result_keys": list(result.keys()) if isinstance(result, dict) else [],
                "output_data": {k: str(v)[:500] for k, v in result.items()} if isinstance(result, dict) else {},
                "duration_ms": int((time.time() - node_start_time) * 1000),
            }}
